- (void)createOrderWithProduct:(WBProductModel *)product payMethod:(NSUInteger)method pageSource:(NSString *)pageSource callback:(WBNetworkBaseCallback)callback {
    NSString *productId = product.apple_product_id;
    BOOL isUpgrade = (product.typeFlags & WBProductTypeFlagUpgrade) != 0;
    NSMutableDictionary *params = [NSMutableDictionary dictionaryWithDictionary:@{
        @"apple_product_id" : productId,
        @"param": @(method),
        @"source": pageSource,
        @"isUpgrade": @(isUpgrade),
        @"paymentMethodId": product.selectedPayMethodId
    }];
    if ([product.selectedPromoModels count]) {
        NSString *promoCodes = [[product.selectedPromoModels valueForKey:NSStringFromSelector(@selector(code))] componentsJoinedByString:@","];
        params[@"codes"] = promoCodes;
    }
    [self POST:@"order/create" params:params callback:callback];
}

// 验证交易订单和收据
- (void)verifyTransactionWithOrderNo:(NSString *)orderNo receiptData:(NSString *)dataStr callback:(WBNetworkBaseCallback)callback {
    NSDictionary *params = @{
        @"order_no" : orderNo,
        @"receipt_data" : dataStr,
    };
    [self POST:@"order/process" params:params callback:callback];
}

- (void)refreshOrderStatus:(NSString *)orderNo callback:(WBNetworkBaseCallback)callback {
    NSDictionary *params = @{
        @"order_no" : orderNo,
    };
    [self POST:@"order/refresh" params:params callback:callback];
}

- (void)getRecentOrdersFromOtherUsersWithCount:(NSUInteger)count callback:(WBOtherUserOrderListCallback)callback {
    NSUInteger maxCount = 50;
    if (count > maxCount) count = maxCount;
    NSDictionary *params = @{
        @"size" : @(count),
    };
    [self POST:@"order/recent" params:params callback:^(id  _Nullable json, NSError * _Nullable error) {
        NSParameterAssert(json == nil ^ error == nil);
        if (error) return callback(nil, error);
        NSArray<WBOtherUserOrderModel *> *orders = [NSArray modelArrayWithClass:[WBOtherUserOrderModel class] json:json];
        return callback(orders, nil);
    }];
}

