            break;
        case WBVappStatusDownloadError:
            [self handleVAppDownloadErrorWithVApp:vapp];
            break;
        case WBVappStatusDownloaded:
        case WBVappStatusWaitingInstall:
        case WBVappStatusInstalling:
            [SVProgressHUD showInfoWithStatus:@"安装中，马上就好"];
            break;
        case WBVappStatusInstallError:
            [SVProgressHUD showInfoWithStatus:@"安装失败，请重试"];
